-- Trendora Synthetic Seed Data (derived from questionnaire responses)

-- Clear existing data so the seed is idempotent
TRUNCATE TABLE
  cart_items, carts, addresses, coupon_usages, order_items, orders, deliveries,
  inventory, product_variants, product_images, reviews, product_promotions,
  category_promotions, product, categories, vendor, customer, payment
CASCADE;

-- VENDORS (33 responses, all fashion businesses, located in Buea)

-- CATEGORIES
;

